/**
 * Integration tests for API shared configuration migration
 * Validates: Requirements 3.1, 3.7
 */
import assert from 'node:assert/strict';
import { describe, it } from 'node:test';
import { ConfigService as SharedConfigService } from '@superboard/backend-shared/config';
import { envSchema, type AppEnv } from '../../src/config/env';

describe('SharedConfigService integration', () => {
  it('loads and validates env variables with the shared config service', () => {
    const original = { ...process.env };
    try {
      process.env.NODE_ENV = 'test';
      process.env.PORT = '4000';
      process.env.DATABASE_URL = 'postgresql://test:test@localhost:5432/test';
      process.env.REDIS_URL = 'redis://localhost:6379';
      process.env.ENABLE_REDIS = 'false';
      process.env.ENABLE_QUEUE = 'false';
      process.env.ELASTICSEARCH_URL = 'http://localhost:9200';
      process.env.QUEUE_NAME = 'superboard-dev';
      process.env.FRONTEND_URL = 'http://localhost:3000';
      process.env.AI_SERVICE_URL = 'http://localhost:8000';
      process.env.JWT_SECRET = '1234567890abcdef';
      process.env.JWT_EXPIRES_IN = '1d';

      const config = new SharedConfigService<AppEnv>({ schema: envSchema, validateOnLoad: true });
      assert.equal(config.get('PORT'), 4000);
      assert.equal(config.get('NODE_ENV'), 'test');
    } finally {
      // Restore env
      for (const key of Object.keys(process.env)) {
        if (!(key in original)) {

          delete (process.env as any)[key];
        }
      }
      Object.assign(process.env, original);
    }
  });
});

/**
 * Integration tests for API global exception filter migration
 * Validates: Requirements 9.1, 9.2, 9.7
 */
import assert from 'node:assert/strict';
import { describe, it } from 'node:test';
import { BadRequestException } from '@nestjs/common';
import { ApiGlobalExceptionFilter } from '../../src/common/filters/api-global-exception.filter';

function makeHost(params: { correlationId?: string } = {}) {
  let statusCode = 200;
  let body: unknown;

  const res: any = {
    status(code: number) {
      statusCode = code;
      return res;
    },
    json(data: unknown) {
      body = data;
      return res;
    },
    getStatusCode: () => statusCode,
    getBody: () => body,
  };

  const req: any = {
    method: 'GET',
    url: '/test',
    headers: {
      'x-correlation-id': params.correlationId ?? 'test-corr',
    },
    body: {},
  };

  const host: any = {
    switchToHttp: () => ({
      getRequest: () => req,
      getResponse: () => res,
    }),
  };

  return { host, res };
}

describe('ApiGlobalExceptionFilter integration', () => {
  it('returns @superboard/shared apiError envelope', () => {
    const filter = new ApiGlobalExceptionFilter({ diagnose: async () => undefined } as never);
    const { host, res } = makeHost({ correlationId: 'corr-123' });

    filter.catch(new BadRequestException('bad'), host);

    assert.equal(res.getStatusCode(), 400);
    const body = res.getBody() as any;
    assert.equal(body.success, false);
    assert.equal(body.data, null);
    assert.equal(body.error.code, 'VALIDATION_FAILED');
    assert.equal(body.error.message, 'bad');
    assert.equal(body.meta.correlationId, 'corr-123');
    assert.ok(typeof body.meta.timestamp === 'string');
  });
});

import assert from 'node:assert/strict';
import { BadRequestException } from '@nestjs/common';
import { describe, it } from 'node:test';
import { WorkflowService } from '../../src/modules/workflow/workflow.service';
import { ProjectService } from '../../src/modules/project/project.service';

type PrismaMock = Record<string, any>;

describe('Workflow Status Policy', () => {
  describe('WorkflowService', () => {
    it('validateTransition allows valid transition', async () => {
      const prisma = {
        projectWorkflowStatus: {
          findFirst: async ({ where }: any) => {
            if (where.key === 'todo') return { id: 's1', name: 'Todo' };
            if (where.key === 'in_progress') return { id: 's2', name: 'In Progress' };
            return null;
          },
        },
        projectWorkflowTransition: {
          findFirst: async () => ({ id: 't1' }),
        },
      } satisfies PrismaMock;

      const service = new WorkflowService(prisma as any);
      await assert.doesNotReject(() => service.validateTransition('p1', 'todo', 'in_progress'));
    });

    it('validateTransition throws BadRequest for invalid transition', async () => {
      const prisma = {
        projectWorkflowStatus: {
          findFirst: async ({ where }: any) => {
            if (where.key === 'todo') return { id: 's1', name: 'Todo' };
            if (where.key === 'done') return { id: 's3', name: 'Done' };
            return null;
          },
        },
        projectWorkflowTransition: {
          findFirst: async () => null,
        },
      } satisfies PrismaMock;

      const service = new WorkflowService(prisma as any);
      await assert.rejects(
        () => service.validateTransition('p1', 'todo', 'done'),
        (error: any) => {
          assert.ok(error instanceof BadRequestException);
          assert.match(error.message, /không cho phép chuyển đổi từ "Todo" sang "Done"/);
          return true;
        },
      );
    });
  });

  describe('ProjectService Integration', () => {
    it('createProject triggers template cloning', async () => {
      let cloneCalled = false;
      const prisma = {
        $executeRaw: async () => undefined,
        project: {
          create: async () => ({
            id: 'p-new',
            name: 'New Project',
            description: null,
            color: null,
            icon: null,
            key: 'NP',
            createdAt: new Date(),
            updatedAt: new Date(),
          }),
        },
      } satisfies PrismaMock;

      const workflowService = {
        cloneWorkspaceTemplateToProject: async () => {
          cloneCalled = true;
        },
      } satisfies Record<string, any>;

      const noopRedisService = {
        del: async () => undefined,
        getJson: async () => null,
        setJson: async () => undefined,
      };
      const noopAiService = { getEmbedding: async () => [], logSignal: async () => true };
      const noopAutomationService = { handleTaskEvent: async () => undefined };

      const service = new ProjectService(
        prisma as any,
        {} as any,
        workflowService as any,
        noopAiService as any,
        noopRedisService as any,
        noopAutomationService as any,
      );

      await service.createProject('w1', { name: 'New Project' });
      assert.strictEqual(cloneCalled, true);
    });
  });
});

/**
 * Integration tests for Automation AMQP consumer migration
 *
 * Validates: Requirements 1.1, 1.4, 1.5
 */

import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import type { ConsumeMessage } from 'amqplib';
import { MetricsService } from '@superboard/backend-shared/metrics';
import type { DomainEvent } from '@superboard/shared';
import { AutomationAmqpConsumerService } from './automation-amqp-consumer.service';

function makeConfigService(values: Record<string, string>) {
  return {
    get: (key: string) => values[key],
  };
}

function buildEvent(eventType: string): DomainEvent {
  return {
    eventId: '01HZZZZZZZZZZZZZZZZZZZZZZZ',
    eventType,
    eventVersion: '1.0',
    producer: 'automation-service',
    correlationId: 'corr-1',
    idempotencyKey: 'idem-1',
    occurredAt: new Date().toISOString(),
    payload: { taskId: 't1', projectId: 'p1', oldStatus: 'todo', newStatus: 'done' },
  };
}

function buildConsumeMessage(body: unknown, correlationId: string = 'corr-1'): ConsumeMessage {
  return {
    content: Buffer.from(JSON.stringify(body), 'utf8'),
    fields: {
      deliveryTag: 1,
      redelivered: false,
      exchange: 'ex',
      routingKey: 'task.created',

    } as any,
    properties: { correlationId, headers: {} },
  } as ConsumeMessage;
}

describe('AutomationAmqpConsumerService', () => {
  it('ACKs supported event types and processes them', async () => {
    const consumer = new AutomationAmqpConsumerService(
      makeConfigService({
        RABBITMQ_URL: 'amqp://localhost:5672',
        RABBITMQ_PREFETCH_COUNT: '10',
      }) as never,
      new MetricsService({
        enabled: true,
        collectDefaultMetrics: false,
        defaultLabels: { service: 'automation' },
      }),
    );

    let acked = false;
    let processed = false;


    (consumer as any).evaluateRules = async () => {
      processed = true;
    };


    (consumer as any).channel = {
      ack: () => {
        acked = true;
      },
      nack: () => {
        throw new Error('should not nack');
      },
      publish: () => true,
    };

    const msg = buildConsumeMessage(buildEvent('task.created'));

    await (consumer as any).onMessage(msg);

    assert.equal(processed, true);
    assert.equal(acked, true);
  });

  it('ACKs unsupported event types without processing', async () => {
    const consumer = new AutomationAmqpConsumerService(
      makeConfigService({
        RABBITMQ_URL: 'amqp://localhost:5672',
        RABBITMQ_PREFETCH_COUNT: '10',
      }) as never,
      new MetricsService({
        enabled: true,
        collectDefaultMetrics: false,
        defaultLabels: { service: 'automation' },
      }),
    );

    let acked = false;
    let processed = false;


    (consumer as any).evaluateRules = async () => {
      processed = true;
    };


    (consumer as any).channel = {
      ack: () => {
        acked = true;
      },
      nack: () => {
        throw new Error('should not nack');
      },
      publish: () => true,
    };

    const msg = buildConsumeMessage(buildEvent('unsupported.event'));

    await (consumer as any).onMessage(msg);

    assert.equal(processed, false);
    assert.equal(acked, true);
  });

  it('routes to DLQ when processing fails', async () => {
    const consumer = new AutomationAmqpConsumerService(
      makeConfigService({
        RABBITMQ_URL: 'amqp://localhost:5672',
        RABBITMQ_PREFETCH_COUNT: '10',
      }) as never,
      new MetricsService({
        enabled: true,
        collectDefaultMetrics: false,
        defaultLabels: { service: 'automation' },
      }),
    );

    let acked = false;
    let published = false;


    (consumer as any).evaluateRules = async () => {
      throw new Error('fail');
    };


    (consumer as any).channel = {
      ack: () => {
        acked = true;
      },
      nack: () => {
        throw new Error('should not nack when DLQ publish works');
      },
      publish: () => {
        published = true;
        return true;
      },
    };

    const msg = buildConsumeMessage(buildEvent('task.created'));

    await (consumer as any).onMessage(msg);

    assert.equal(published, true);
    assert.equal(acked, true);
  });
});

/**
 * Property Test: Dead Letter Queue Routing Consistency
 *
 * **Validates: Requirements 1.4, 4.5**
 *
 * For any failing message, the consumer SHALL route to DLQ and preserve
 * correlation ID + original message metadata.
 */

import fc from 'fast-check';
import type { ConsumeMessage } from 'amqplib';
import { BaseAMQPConsumer } from '../base-consumer';
import type { AMQPConfig, DeadLetterQueueConfig } from '../types';

class FailingConsumer extends BaseAMQPConsumer<Record<string, unknown>> {
  protected async processMessage(): Promise<void> {
    throw new Error('boom');
  }
}

function buildConsumeMessage(params: {
  content: Buffer;
  correlationId?: string;
  routingKey: string;
  exchange: string;
}): ConsumeMessage {
  return {
    content: params.content,
    fields: {
      deliveryTag: 1,
      redelivered: false,
      exchange: params.exchange,
      routingKey: params.routingKey,

    } as any,
    properties: {
      correlationId: params.correlationId,
      headers: {},
    },
  } as ConsumeMessage;
}

describe('Property 8: Dead Letter Queue Routing Consistency', () => {
  it('should publish enriched DLQ message with preserved metadata', async () => {
    await fc.assert(
      fc.asyncProperty(
        fc.string({ minLength: 1, maxLength: 64 }),
        fc.string({ minLength: 1, maxLength: 64 }),
        fc.string({ minLength: 1, maxLength: 64 }),
        fc.jsonValue().map((o: unknown) => Buffer.from(JSON.stringify(o), 'utf8')),
        async (exchange: string, queue: string, correlationId: string, content: Buffer) => {
          const config: AMQPConfig = {
            url: 'amqp://localhost:5672',
            exchange,
            queue,
            routingKeys: ['test.*'],
            deadLetterExchange: `${exchange}.dlx`,
            deadLetterQueue: `${queue}.dlq`,
          };

          const deadLetter: DeadLetterQueueConfig = {
            exchange: config.deadLetterExchange!,
            queue: config.deadLetterQueue!,
            routingKey: queue,
          };

          let published: {
            exchange: string;
            routingKey: string;
            content: string;
            options: any;
          } | null = null;
          let acked = false;
          let nacked = false;

          const consumer = new FailingConsumer({
            config,
            serviceName: 'test-service',
            deadLetter,
            parseMessage: () => ({ any: 'payload' }),
            logger: {
              debug: () => {},
              log: () => {},
              warn: () => {},
              error: () => {},
            },
          });

          // Inject stub channel

          (consumer as any).channel = {
            publish: (ex: string, rk: string, buf: Buffer, options: any) => {
              published = { exchange: ex, routingKey: rk, content: buf.toString('utf8'), options };
              return true;
            },
            ack: () => {
              acked = true;
            },
            nack: () => {
              nacked = true;
            },
          };

          const msg = buildConsumeMessage({
            content,
            correlationId,
            routingKey: 'test.key',
            exchange,
          });


          await (consumer as any).onMessage(msg);

          expect(acked).toBe(true);
          expect(nacked).toBe(false);
          expect(published).not.toBeNull();
          expect(published!.exchange).toBe(deadLetter.exchange);
          expect(published!.routingKey).toBe(deadLetter.routingKey);
          expect(published!.options.correlationId).toBe(correlationId);
          expect(published!.options.headers['x-original-queue']).toBe(queue);

          const parsed = JSON.parse(published!.content) as {
            error: { message: string };
            context: { correlationId: string; originalMessage: { contentBase64: string } };
          };

          expect(parsed.error.message).toBe('boom');
          expect(parsed.context.correlationId).toBe(correlationId);
          expect(parsed.context.originalMessage.contentBase64).toBe(content.toString('base64'));
        },
      ),
      { numRuns: 100 },
    );
  });

  it('should nack when DLQ publish fails', async () => {
    const config: AMQPConfig = {
      url: 'amqp://localhost:5672',
      exchange: 'ex',
      queue: 'q',
      routingKeys: ['k'],
      deadLetterExchange: 'dlx',
      deadLetterQueue: 'dlq',
    };

    const consumer = new FailingConsumer({
      config,
      serviceName: 'test-service',
      deadLetter: { exchange: 'dlx', queue: 'dlq', routingKey: 'q' },
      parseMessage: () => ({ any: 'payload' }),
      logger: {
        debug: () => {},
        log: () => {},
        warn: () => {},
        error: () => {},
      },
    });

    let acked = false;
    let nacked = false;


    (consumer as any).channel = {
      publish: () => {
        throw new Error('publish failed');
      },
      ack: () => {
        acked = true;
      },
      nack: () => {
        nacked = true;
      },
    };

    const msg = buildConsumeMessage({
      content: Buffer.from('{"x":1}', 'utf8'),
      correlationId: 'corr-1',
      routingKey: 'k',
      exchange: 'ex',
    });


    await (consumer as any).onMessage(msg);

    expect(acked).toBe(false);
    expect(nacked).toBe(true);
  });
});

/**
 * Property Test: Bootstrap Configuration Consistency
 *
 * **Validates: Requirements 6.3, 6.4, 6.7**
 */

import fc from 'fast-check';
import { resolveListenPort } from '../nest-bootstrap';

describe('Property 11: Bootstrap Configuration Consistency', () => {
  it('should deterministically resolve a positive listen port', async () => {
    await fc.assert(
      fc.asyncProperty(
        fc.oneof(fc.constant(undefined), fc.integer({ min: -1000, max: 70000 })),
        fc.oneof(fc.constant(undefined), fc.string({ minLength: 0, maxLength: 6 })),
        async (configPort, envPort) => {
          const port = resolveListenPort(configPort as any, envPort as any);
          expect(typeof port).toBe('number');
          expect(Number.isFinite(port)).toBe(true);
          expect(port).toBeGreaterThan(0);
        },
      ),
      { numRuns: 100 },
    );
  });
});

/**
 * Property-Based Tests for Configuration Round-trip Consistency
 *
 * **Validates: Requirements 1.7, 3.6**
 *
 * Property 2: Configuration Round-trip Consistency
 * For any valid configuration object, serializing and deserializing the configuration
 * SHALL produce an equivalent configuration with all required fields preserved.
 */

import * as fc from 'fast-check';
import { ConfigService } from '../config.service';
import {
  AMQPConfigSchema,
  RedisConfigSchema,
  DatabaseConfigSchema,
  HealthConfigSchema,
  MetricsConfigSchema,
  BootstrapConfigSchema,
} from '../validators';

describe('Property 2: Configuration Round-trip Consistency', () => {
  /**
   * Test generators for various configuration types
   */

  // Generator for valid AMQP configuration
  const validAMQPConfigArb = fc.record({
    url: fc.constant('amqp://localhost:5672'),
    exchange: fc.string({ minLength: 1, maxLength: 50 }),
    queue: fc.string({ minLength: 1, maxLength: 50 }),
    routingKeys: fc.array(fc.string({ minLength: 1, maxLength: 20 }), {
      minLength: 1,
      maxLength: 5,
    }),
    prefetchCount: fc
      .option(fc.integer({ min: 1, max: 1000 }), { freq: 2 })
      .filter((v) => v !== null),
    reconnectInterval: fc
      .option(fc.integer({ min: 1000, max: 60000 }), { freq: 2 })
      .filter((v) => v !== null),
    maxReconnectAttempts: fc
      .option(fc.integer({ min: 1, max: 50 }), { freq: 2 })
      .filter((v) => v !== null),
    deadLetterExchange: fc
      .option(fc.string({ minLength: 1, maxLength: 50 }), { freq: 2 })
      .filter((v) => v !== null),
    deadLetterQueue: fc
      .option(fc.string({ minLength: 1, maxLength: 50 }), { freq: 2 })
      .filter((v) => v !== null),
  });

  // Generator for valid Redis configuration
  const validRedisConfigArb = fc.record({
    host: fc.string({ minLength: 1, maxLength: 100 }),
    port: fc.integer({ min: 1, max: 65535 }),
    password: fc
      .option(fc.string({ minLength: 1, maxLength: 100 }), { freq: 2 })
      .filter((v) => v !== null),
    db: fc.option(fc.integer({ min: 0, max: 15 }), { freq: 2 }).filter((v) => v !== null),
    maxRetriesPerRequest: fc
      .option(fc.integer({ min: 1, max: 10 }), { freq: 2 })
      .filter((v) => v !== null),
    retryDelayOnFailover: fc
      .option(fc.integer({ min: 1, max: 1000 }), { freq: 2 })
      .filter((v) => v !== null),
    lazyConnect: fc.option(fc.boolean(), { freq: 2 }).filter((v) => v !== null),
  });

  // Generator for valid Database configuration
  const validDatabaseConfigArb = fc.record({
    host: fc.string({ minLength: 1, maxLength: 100 }),
    port: fc.integer({ min: 1, max: 65535 }),
    database: fc.string({ minLength: 1, maxLength: 50 }),
    username: fc.string({ minLength: 1, maxLength: 50 }),
    password: fc.string({ minLength: 1, maxLength: 100 }),
    ssl: fc.option(fc.boolean(), { freq: 2 }).filter((v) => v !== null),
    connectionTimeoutMillis: fc
      .option(fc.integer({ min: 1000, max: 120000 }), { freq: 2 })
      .filter((v) => v !== null),
    idleTimeoutMillis: fc
      .option(fc.integer({ min: 1000, max: 120000 }), { freq: 2 })
      .filter((v) => v !== null),
    max: fc.option(fc.integer({ min: 1, max: 100 }), { freq: 2 }).filter((v) => v !== null),
  });

  // Generator for valid Health configuration
  const validHealthConfigArb = fc.record({
    endpoints: fc.record({
      health: fc.string({ minLength: 1, maxLength: 50 }),
      ready: fc.string({ minLength: 1, maxLength: 50 }),
    }),
    dependencies: fc.array(
      fc.record({
        name: fc.string({ minLength: 1, maxLength: 50 }),
        type: fc.constantFrom('database', 'redis', 'rabbitmq', 'grpc', 'http'),
        config: fc.record({ timeout: fc.integer({ min: 1000, max: 30000 }) }),
        timeout: fc
          .option(fc.integer({ min: 1000, max: 30000 }), { freq: 2 })
          .filter((v) => v !== null),
      }),
      { maxLength: 3 },
    ),
  });

  // Generator for valid Metrics configuration
  const validMetricsConfigArb = fc.record({
    enabled: fc.option(fc.boolean(), { freq: 2 }).filter((v) => v !== null),
    prefix: fc
      .option(fc.string({ minLength: 1, maxLength: 50 }), { freq: 2 })
      .filter((v) => v !== null),
    defaultLabels: fc
      .option(
        fc.record({
          service: fc.string({ minLength: 1, maxLength: 50 }),
          environment: fc.constantFrom('dev', 'staging', 'prod'),
        }),
        { freq: 2 },
      )
      .filter((v) => v !== null),
    collectDefaultMetrics: fc.option(fc.boolean(), { freq: 2 }).filter((v) => v !== null),
  });

  // Generator for valid Bootstrap configuration
  const validBootstrapConfigArb = fc.record({
    port: fc.option(fc.integer({ min: 1, max: 65535 }), { freq: 2 }).filter((v) => v !== null),
    globalPrefix: fc
      .option(fc.string({ minLength: 1, maxLength: 50 }), { freq: 2 })
      .filter((v) => v !== null),
    cors: fc
      .option(
        fc.record({
          origin: fc
            .option(fc.constantFrom(true, false, 'http://localhost:3000'), { freq: 2 })
            .filter((v) => v !== null),
          credentials: fc.option(fc.boolean(), { freq: 2 }).filter((v) => v !== null),
        }),
        { freq: 2 },
      )
      .filter((v) => v !== null),
    gracefulShutdownTimeout: fc
      .option(fc.integer({ min: 1000, max: 120000 }), { freq: 2 })
      .filter((v) => v !== null),
  });

  /**
   * Helper function to serialize configuration to JSON
   */
  const serializeConfig = (config: Record<string, unknown>): string => {
    return JSON.stringify(config);
  };

  /**
   * Helper function to deserialize configuration from JSON
   */
  const deserializeConfig = (json: string): Record<string, unknown> => {
    return JSON.parse(json);
  };

  /**
   * Helper function to check if two configurations are equivalent
   * Handles optional fields and default values
   */
  const areConfigsEquivalent = (original: unknown, deserialized: unknown): boolean => {
    // Check if both are objects
    if (typeof original !== 'object' || typeof deserialized !== 'object') {
      return original === deserialized;
    }

    // Check if both are null
    if (original === null && deserialized === null) {
      return true;
    }

    // Check if one is null and the other is not
    if ((original === null) !== (deserialized === null)) {
      return false;
    }

    // Check if both are arrays
    if (Array.isArray(original) && Array.isArray(deserialized)) {
      if (original.length !== deserialized.length) {
        return false;
      }
      return original.every((item, index) => areConfigsEquivalent(item, deserialized[index]));
    }

    // Check if both are objects (but not arrays)
    if (Array.isArray(original) !== Array.isArray(deserialized)) {
      return false;
    }

    // Compare object keys
    const originalKeys = Object.keys(original as any).sort();
    const deserializedKeys = Object.keys(deserialized as any).sort();

    if (originalKeys.length !== deserializedKeys.length) {
      return false;
    }

    // Compare each key-value pair
    return originalKeys.every((key) => {
      if (!deserializedKeys.includes(key)) {
        return false;
      }
      return areConfigsEquivalent(
        (original as Record<string, unknown>)[key],
        (deserialized as Record<string, unknown>)[key],
      );
    });
  };

  /**
   * Property Test: AMQP configuration round-trip consistency
   */
  it('should maintain AMQP configuration consistency through serialization round-trip', () => {
    fc.assert(
      fc.property(validAMQPConfigArb, (originalConfig: Record<string, unknown>) => {
        // Create ConfigService with original config
        const configService = new ConfigService({
          schema: AMQPConfigSchema,
          envOverrides: originalConfig,
          validateOnLoad: true,
        });

        // Get the configuration
        const config = configService.getAll();

        // Serialize to JSON
        const serialized = serializeConfig(config);

        // Deserialize from JSON
        const deserialized = deserializeConfig(serialized);

        // Verify equivalence
